  struct HexByte: ParserPrinter {
    func parse(_ input: inout Substring.UTF8View) throws -> UInt8 {
      let prefix = input.prefix(2)
      guard
        prefix.count == 2,
        let byte = UInt8(String(decoding: prefix, as: UTF8.self), radix: 16)
      else { throw ParsingError() }
      input.removeFirst(2)
      return byte
