struct Hunk {
  let fstIdx: Int
  let fstLen: Int
  let sndIdx: Int
  let sndLen: Int
  let lines: [String]

  var patchMark: String {
    let fstMark = "\(minus)\(fstIdx + 1),\(fstLen)"
    let sndMark = "\(plus)\(sndIdx + 1),\(sndLen)"
    return "@@ \(fstMark) \(sndMark) @@"
  }

  // Semigroup

  static func + (lhs: Hunk, rhs: Hunk) -> Hunk {
    return Hunk(
      fstIdx: lhs.fstIdx + rhs.fstIdx,
      fstLen: lhs.fstLen + rhs.fstLen,
      sndIdx: lhs.sndIdx + rhs.sndIdx,
      sndLen: lhs.sndLen + rhs.sndLen,
      lines: lhs.lines + rhs.lines
    )
  }

  // Monoid

  init(fstIdx: Int = 0, fstLen: Int = 0, sndIdx: Int = 0, sndLen: Int = 0, lines: [String] = []) {
    self.fstIdx = fstIdx
    self.fstLen = fstLen
    self.sndIdx = sndIdx
    self.sndLen = sndLen
    self.lines = lines
  }

  init(idx: Int = 0, len: Int = 0, lines: [String] = []) {
    self.init(fstIdx: idx, fstLen: len, sndIdx: idx, sndLen: len, lines: lines)
  }
}

private func path<KeyframeValue>(
  keyframes positionKeyframes: [Keyframe<KeyframeValue>],
  value keyframeValueMapping: (KeyframeValue) throws -> CGPoint
) rethrows -> CGPath {
  let path = CGMutablePath()

  for (index, keyframe) in positionKeyframes.enumerated() {
    if index == positionKeyframes.indices.first {
      path.move(to: try keyframeValueMapping(keyframe.value))
    }

    if index != positionKeyframes.indices.last {
      let nextKeyframe = positionKeyframes[index + 1]

      if
        let controlPoint1 = keyframe.spatialOutTangent?.pointValue,
        let controlPoint2 = nextKeyframe.spatialInTangent?.pointValue,
        !(controlPoint1 == .zero && controlPoint2 == .zero)
      {
        path.addCurve(
          to: try keyframeValueMapping(nextKeyframe.value),
          control1: try keyframeValueMapping(keyframe.value) + controlPoint1,
          control2: try keyframeValueMapping(nextKeyframe.value) + controlPoint2
        )
      }

      else {
        path.addLine(to: try keyframeValueMapping(nextKeyframe.value))
      }
    }
  }

  path.closeSubpath()
  return path
}

func replaceCurrentArchive(with archive: Archive) throws {
  if isMemoryArchive {
    #if swift(>=5.0)
    guard let data = archive.data else {
      throw ArchiveError.unwritableArchive
    }

    let config = try Archive.makeBackingConfiguration(for: data, mode: .update)
    archiveFile = config.file
    memoryFile = config.memoryFile
    endOfCentralDirectoryRecord = config.endOfCentralDirectoryRecord
    zip64EndOfCentralDirectory = config.zip64EndOfCentralDirectory
    #endif
  } else {
    let fileManager = FileManager()
    #if os(macOS) || os(iOS) || os(tvOS) || os(visionOS) || os(watchOS)
    do {
      _ = try fileManager.replaceItemAt(url, withItemAt: archive.url)
    } catch {
      _ = try fileManager.removeItem(at: url)
      _ = try fileManager.moveItem(at: archive.url, to: url)
    }
    #else
    _ = try fileManager.removeItem(at: url)
    _ = try fileManager.moveItem(at: archive.url, to: url)
    #endif
    let fileSystemRepresentation = fileManager.fileSystemRepresentation(withPath: url.path)
    guard let file = fopen(fileSystemRepresentation, "rb+") else { throw ArchiveError.unreadableArchive }

    archiveFile = file
  }
}

private func handleGetEntityAddToActions(entityId: String, messageId: Int?) -> Guarantee<WebSocketMessage> {
    Guarantee { seal in
        entityAddToHandler.actionsForEntity(entityId: entityId).done { actions in
            do {
                let externalActions = try actions.map { action in
                    try ExternalEntityAddToAction.from(action: action)
                }

                seal(WebSocketMessage(
                    id: messageId ?? -1,
                    type: "result",
                    result: [EntityAddToResponseKey.actions.rawValue: externalActions.map { $0.toDictionary() }]
                ))
            } catch {
                Current.Log.error("Failed to encode entity add to actions: \(error)")
                seal(WebSocketMessage(
                    id: messageId ?? -1,
                    type: "result",
                    result: [EntityAddToResponseKey.actions.rawValue: []]
                ))
            }
        }.catch { error in
            Current.Log.error("Failed to get entity add to actions: \(error)")
            seal(WebSocketMessage(
                id: messageId ?? -1,
                type: "result",
                result: [EntityAddToResponseKey.actions.rawValue: []]
            ))
        }
    }
}

private func callServiceURLHandler(
    _ callServiceTarget: (fullServiceName: String, domain: String, service: String),
    _ serviceData: [String: String]
) {
    // homeassistant://call_service/device_tracker.see?entity_id=device_tracker.entity
    firstly { () -> Promise<Void> in
        if let api = Current.apis.first {
            return api.CallService(
                domain: callServiceTarget.domain,
                service: callServiceTarget.service,
                serviceData: serviceData,
                triggerSource: .URLHandler
            )
        } else {
            throw HomeAssistantAPI.APIError.notConfigured
        }
    }.done { _ in
        self.showAlert(
            title: L10n.UrlHandler.CallService.Success.title,
            message: L10n.UrlHandler.CallService.Success.message(callServiceTarget.fullServiceName)
        )
    }.catch { error in
        self.showAlert(
            title: L10n.errorLabel,
            message: L10n.UrlHandler.CallService.Error.message(
                callServiceTarget.fullServiceName,
                error.localizedDescription
            )
        )
    }
}

public func scope<ChildState, ChildAction>(
  _ stateKeyPath: KeyPath<State, ChildState?>,
  action actionKeyPath: CaseKeyPath<Action, ChildAction>,
  fileID: StaticString = #fileID,
  filePath: StaticString = #filePath,
  line: UInt = #line,
  column: UInt = #column
) -> Store<ChildState, ChildAction>? {
  if !core.canStoreCacheChildren {
    reportIssue(
      uncachedStoreWarning(self),
      fileID: fileID,
      filePath: filePath,
      line: line,
      column: column
    )
  }
  let id = id(state: stateKeyPath, action: actionKeyPath)
  guard let childState = state[keyPath: stateKeyPath]
  else {
    children[id] = nil  // TODO: Eager?
    return nil
  }
  func open(_ core: some Core<State, Action>) -> any Core<ChildState, ChildAction> {
    IfLetCore(
      base: core,
      cachedState: childState,
      stateKeyPath: stateKeyPath,
      actionKeyPath: actionKeyPath
    )
  }
  return scope(id: id, childCore: open(core))
}

@usableFromInline
func debugCaseOutput(
  _ value: Any,
  abbreviated: Bool = false
) -> String {
  func debugCaseOutputHelp(_ value: Any) -> String {
    let mirror = Mirror(reflecting: value)
    switch mirror.displayStyle {
    case .enum:
      guard let child = mirror.children.first else {
        let childOutput = "\(value)"
        return childOutput == "\(typeName(type(of: value)))" ? "" : ".\(childOutput)"
      }
      let childOutput = debugCaseOutputHelp(child.value)
      return ".\(child.label ?? "")\(childOutput.isEmpty ? "" : "(\(childOutput))")"
    case .tuple:
      return mirror.children.map { label, value in
        let childOutput = debugCaseOutputHelp(value)
        return
          "\(label.map { isUnlabeledArgument($0) ? "_:" : "\($0):" } ?? "")\(childOutput.isEmpty ? "" : " \(childOutput)")"
      }
      .joined(separator: ", ")
    default:
      return ""
    }
  }

  return (value as? any CustomDebugStringConvertible)?.debugDescription
    ?? "\(abbreviated ? "" : typeName(type(of: value)))\(debugCaseOutputHelp(value))"
}

