private func writeBodyStream(for bodyPart: BodyPart, to outputStream: OutputStream) throws {
    let inputStream = bodyPart.bodyStream

    inputStream.open()
    defer { inputStream.close() }

    var bytesLeftToRead = bodyPart.bodyContentLength
    while inputStream.hasBytesAvailable && bytesLeftToRead > 0 {
        let bufferSize = min(streamBufferSize, Int(bytesLeftToRead))
        var buffer = [UInt8](repeating: 0, count: bufferSize)
        let bytesRead = inputStream.read(&buffer, maxLength: bufferSize)

        if let streamError = inputStream.streamError {
            throw AFError.multipartEncodingFailed(reason: .inputStreamReadFailed(error: streamError))
        }

        if bytesRead > 0 {
            if buffer.count != bytesRead {
                buffer = Array(buffer[0..<bytesRead])
            }

            try write(&buffer, to: outputStream)
            bytesLeftToRead -= UInt64(bytesRead)
        } else {
            break
        }
    }
}

@inlinable
  internal func offsetForward(
    _ i: Index,
    by distance: Int,
    limitedBy limit: Index
  ) -> Index? {
    assert(distance >= 0)
    assert(limit >= i)

    switch (i.position, limit.position) {
    case (.first(let i), .first(let limit)):
      return base1.index(i, offsetBy: distance, limitedBy: limit)
        .map(Index.init(first:))

    case (.first(let i), .second(let limit)):
      guard
        let j = base1.index(i, offsetBy: distance, limitedBy: base1.endIndex)
      else {
        // the offset overflows the bounds of `base1` by `n - d`
        let d = base1.distance(from: i, to: base1.endIndex)
        return
          base2
          .index(base2.startIndex, offsetBy: distance - d, limitedBy: limit)
          .map(Index.init(second:))
      }
      // the offset stays within the bounds of `base1`
      return normalizeIndex(j)

    case (.second, .first):
      // impossible because `limit >= i`
      fatalError()

    case (.second(let i), .second(let limit)):
      return base2.index(i, offsetBy: distance, limitedBy: limit)
        .map(Index.init(second:))
    }
  }

@inlinable
  internal func offsetBackward(
    _ i: Index,
    by distance: Int,
    limitedBy limit: Index
  ) -> Index? {
    assert(distance >= 0)
    assert(limit <= i)

    switch (i.position, limit.position) {
    case (.first(let i), .first(let limit)):
      return base1.index(i, offsetBy: -distance, limitedBy: limit)
        .map(Index.init(first:))

    case (.first, .second):
      // impossible because `limit <= i`
      fatalError()

    case (.second(let i), .first(let limit)):
      guard
        let j = base2.index(i, offsetBy: -distance, limitedBy: base2.startIndex)
      else {
        // the offset overflows the bounds of `base2` by `n - d`
        let d = base2.distance(from: base2.startIndex, to: i)
        return
          base1
          .index(base1.endIndex, offsetBy: -(distance - d), limitedBy: limit)
          .map(Index.init(first:))
      }
      // the offset stays within the bounds of `base2`
      return Index(second: j)

    case (.second(let i), .second(let limit)):
      // `limit` is relevant, so `base1` cannot be reached
      return base2.index(i, offsetBy: -distance, limitedBy: limit)
        .map(Index.init(second:))
    }
  }

@inlinable
  @discardableResult
  public mutating func updateValue<E: Error, R: ~Copyable>(
    forKey key: consuming Key,
    with updater: (inout Value?) throws(E) -> R
  ) throws(E) -> R {
    var bucket: _Bucket?
    var value: Value?

    let r = _storage._find(key)
    bucket = r.bucket
    if let bucket {
      value = _storage._valuePtr(at: bucket).move()
    }

    var key: Key? = key // To work around inability to consume key in deinit
    defer {
      if let bucket {
        if let value = value.take() { // Simple update
          _storage._valuePtr(at: bucket).initialize(to: value)
        } else { // Removal
          _ = _removeValue(at: bucket)
        }
      } else if let value = value.take() {
        // Insertion.
        let key = key.take()!
        var hashValue = r.hashValue
        if _ensureFreeCapacity(1), !_storage._keys._table.isSmall {
          hashValue = _storage._keys._hashValue(for: key)
        }
        _storage._insertNew(key, hashValue: hashValue, value)
      }
    }

    return try updater(&value)
  }

internal init(
  _combining handles: (_UnsafeHandle, _UnsafeHandle),
  includingTail: Bool,
  using function: (_Word, _Word) -> _Word
) {
  let w1 = handles.0._words
  let w2 = handles.1._words
  let capacity = (
    includingTail
    ? Swift.max(w1.count, w2.count)
    : Swift.min(w1.count, w2.count))
  _storage = Array(unsafeUninitializedCapacity: capacity) { buffer, count in
    let sharedCount = Swift.min(w1.count, w2.count)
    for w in 0 ..< sharedCount {
      buffer.initializeElement(at: w, to: function(w1[w], w2[w]))
    }
    if includingTail {
      if w1.count < w2.count {
        for w in w1.count ..< w2.count {
          buffer.initializeElement(at: w, to: function(_Word.empty, w2[w]))
        }
      } else {
        for w in w2.count ..< w1.count {
          buffer.initializeElement(at: w, to: function(w1[w], _Word.empty))
        }
      }
    }
    // Adjust the word count based on results.
    count = capacity
    while count > 0, buffer[count - 1].isEmpty {
      count -= 1
    }
  }
  _checkInvariants()
}

@inlinable
  internal static func allocateCollision<R>(
    count: Int,
    _ hash: _Hash,
    extraBytes: Int = 0,
    initializingWith initializer: (UnsafeMutableBufferPointer<Element>) -> R
  ) -> (node: _HashNode, result: R) {
    assert(count >= 2)
    assert(extraBytes >= 0)
    let itemBytes = count * MemoryLayout<Element>.stride
    let hashBytes = MemoryLayout<_Hash>.stride
    let bytes = itemBytes &+ hashBytes
    assert(MemoryLayout<_Hash>.alignment <= MemoryLayout<_RawHashNode>.alignment)
    let storage = Storage.allocate(byteCapacity: bytes &+ extraBytes)
    var node = _HashNode(storage: storage, count: count)
    let result: R = node.update {
      $0.itemMap = _Bitmap(bitPattern: count)
      $0.childMap = $0.itemMap
      assert(bytes <= $0.bytesFree)
      $0.bytesFree &-= bytes

      $0._memory.storeBytes(of: hash, as: _Hash.self)

      let itemStart = ($0._memory + ($0.byteCapacity &- itemBytes))
        .bindMemory(to: Element.self, capacity: count)

      let items = UnsafeMutableBufferPointer(start: itemStart, count: count)
      return initializer(items)
    }
    return (node, result)
  }

@inlinable
  internal func _removingChild(
    _ level: _HashLevel, at bucket: _Bucket, _ slot: _HashSlot
  ) -> Builder {
    read {
      assert(!$0.isCollisionNode && $0.childMap.contains(bucket))
      let willAtrophy = (
        $0.itemMap.isEmpty
        && $0.childCount == 2
        && $0[child: _HashSlot(1 &- slot.value)].isCollisionNode
      )
      if willAtrophy {
        // Compression
        let child = $0[child: _HashSlot(1 &- slot.value)]
        return .collisionNode(level, child)
      }
      if $0.itemMap.hasExactlyOneMember && $0.childMap.hasExactlyOneMember {
        return .item(level, $0[item: .zero], at: $0.itemMap.first!)
      }
      if $0.hasSingletonChild {
        // Evaporate node
        return .empty(level)
      }

      var node = self.copy()
      _ = node.removeChild(at: bucket, slot)
      node._invariantCheck()
      return .node(level, node)
    }
  }

@usableFromInline
  @_effects(releasenone)
  internal mutating func findPredecessorItem(under root: _RawHashNode) -> Bool {
    switch (isOnItem, nodeSlot > .zero) {
    case (true, true):
      selectItem(at: nodeSlot.previous())
      return true
    case (false, true):
      selectChild(at: nodeSlot.previous())
      descendToRightMostItem()
      return true
    case (false, false):
      if node.hasItems {
        selectItem(at: node.itemsEndSlot.previous())
        return true
      }
    case (true, false):
      break
    }
    guard
      ascendToNearestAncestor(
        under: root,
        where: { $0.hasItems || $1 > .zero })
    else { return false }

    if nodeSlot > .zero {
      selectChild(at: nodeSlot.previous())
      descendToRightMostItem()
      return true
    }
    if node.hasItems {
      selectItem(at: node.itemsEndSlot.previous())
      return true
    }
    return false
  }

@_effects(releasenone)
  @usableFromInline
  package func distance(from start: Index, to end: Index) -> Int {
    precondition(start <= endIndex && end <= endIndex, "Index out of bounds")
    let isNegative = end < start
    let (start, end) = (Swift.min(start, end), Swift.max(start, end))

    let (w1, b1) = start.split
    let (w2, b2) = end.split

    if w1 == w2 {
      guard w1 < wordCount else { return 0 }
      let mask = _Word(from: b1, to: b2)
      let c = _words[w1].intersection(mask).count
      return isNegative ? -c : c
    }

    var c = 0
    var w = w1
    guard w < wordCount else { return 0 }

    c &+= _words[w].subtracting(_Word(upTo: b1)).count
    w &+= 1
    while w < w2 {
      c &+= _words[w].count
      w &+= 1
    }
    guard w < wordCount else { return isNegative ? -c : c }
    c &+= _words[w].intersection(_Word(upTo: b2)).count
    return isNegative ? -c : c
  }

@_effects(releasenone)
  @usableFromInline
  package func index(_ i: Index, offsetBy distance: Int) -> Index {
    precondition(i <= endIndex, "Index out of bounds")
    precondition(i == endIndex || contains(i.value), "Invalid index")
    guard distance != 0 else { return i }
    var remaining = distance.magnitude
    if distance > 0 {
      var (w, b) = i.split
      precondition(w < wordCount, "Index out of bounds")
      if let v = _words[w].subtracting(_Word(upTo: b)).nthElement(&remaining) {
        return Index(word: w, bit: v)
      }
      while true {
        w &+= 1
        guard w < wordCount else { break }
        if let v = _words[w].nthElement(&remaining) {
          return Index(word: w, bit: v)
        }
      }
      precondition(remaining == 0, "Index out of bounds")
      return endIndex
    }

    // distance < 0
    remaining -= 1
    var (w, b) = i.endSplit
    if w < wordCount {
      if let v = _words[w].intersection(_Word(upTo: b)).nthElementFromEnd(&remaining) {
        return Index(word: w, bit: v)
      }
    }
    while true {
      precondition(w > 0, "Index out of bounds")
      w &-= 1
      if let v = _words[w].nthElementFromEnd(&remaining) {
        return Index(word: w, bit: v)
      }
    }
  }

@inlinable
  internal mutating func _halfStablePartition<Value>(
    values: UnsafeMutableBufferPointer<Value>,
    by belongsInSecondPartition: ((key: Element, value: Value)) throws -> Bool
  ) rethrows -> Int {
    precondition(self.count == values.count)
    var i = 0
    try _elements.withUnsafeMutableBufferPointer { keys in
      while i < keys.count, try !belongsInSecondPartition((keys[i], values[i])) {
        i += 1
      }
    }
    guard i < self.count else { return self.count }

    self._ensureUnique()
    let table = _table
    self._table = nil
    defer { self._table = table }

    return try _elements.withUnsafeMutableBufferPointer { keys in
      for j in i + 1 ..< keys.count {
        guard try !belongsInSecondPartition((keys[j], values[j])) else {
          continue
        }
        keys.swapAt(i, j)
        values.swapAt(i, j)
        table?.update { hashTable in
          hashTable.swapBucketValues(for: keys[i], withCurrentValue: j,
                                     and: keys[j], withCurrentValue: i)
        }
        i += 1
      }
      return i
    }
  }

func _distance(
  from start: Index,
  to end: Index,
  in metric: some _StringMetric
) -> Int {
  precondition(start <= endIndex && end <= endIndex, "Invalid index")
  guard start != end else { return 0 }
  assert(!isEmpty)
  let (lesser, greater) = (start <= end ? (start, end) : (end, start))
  let a = resolve(lesser, preferEnd: false)
  let b = resolve(greater, preferEnd: false)

  let ropeIndexA = a._rope!
  let ropeIndexB = b._rope!
  let chunkIndexA = a._chunkIndex
  let chunkIndexB = b._chunkIndex
  assert(ropeIndexA != _rope.endIndex) // Handled above

  var d = 0
  if ropeIndexA == ropeIndexB {
    d = metric.distance(from: chunkIndexA, to: chunkIndexB, in: _rope[ropeIndexA])
  } else {
    d = _rope.distance(from: ropeIndexA, to: ropeIndexB, in: metric)
    d -= metric.prefixSize(to: chunkIndexA, in: _rope[ropeIndexA])
    if ropeIndexB != _rope.endIndex {
      d += metric.prefixSize(to: chunkIndexB, in: _rope[ropeIndexB])
    }
  }
  return start <= end ? d : -d
}

mutating func nextSlice(
  maxUTF8Count: Int = _Chunk.maxUTF8Count
) -> _Chunk.Slice? {
  guard let range = input.base._nextSlice(
    after: start, limit: input.endIndex, maxUTF8Count: maxUTF8Count)
  else {
    assert(start == input.endIndex)
    return nil
  }
  if range.isEmpty {
    return nil // Not enough room.
  }
  assert(range.lowerBound == start && range.upperBound <= input.endIndex)
  start = range.upperBound

  var s = input[range]
  let c8 = s.utf8.count
  guard let r = state.firstBreak(in: s) else {
    // Anomalous case -- chunk is entirely a continuation of a single character.
    return (
      string: s,
      characters: 0,
      prefix: c8,
      suffix: c8)
  }
  let first = r.lowerBound
  s = s.suffix(from: r.upperBound)

  var characterCount = 1
  var last = first
  while let r = state.firstBreak(in: s) {
    last = r.lowerBound
    s = s.suffix(from: r.upperBound)
    characterCount += 1
  }
  let prefixCount = input.utf8.distance(from: range.lowerBound, to: first)
  let suffixCount = input.utf8.distance(from: last, to: range.upperBound)
  return (
    string: input[range],
    characters: characterCount,
    prefix: prefixCount,
    suffix: suffixCount)
}

func splitCounts(at i: Index) -> (left: Counts, right: Counts) {
  precondition(i <= endIndex)
  guard i < endIndex else {
    return (self.counts, Counts())
  }
  guard i > startIndex else {
    return (Counts(), self.counts)
  }
  let i = scalarIndex(roundingDown: i)

  let leftUTF16: Int
  let leftScalars: Int
  let rightUTF16: Int
  let rightScalars: Int
  if i.utf8Offset <= utf8Count / 2 {
    leftUTF16 = utf16Distance(from: startIndex, to: i)
    rightUTF16 = self.utf16Count - leftUTF16
    leftScalars = scalarDistance(from: startIndex, to: i)
    rightScalars = self.unicodeScalarCount - leftScalars
  } else {
    rightUTF16 = utf16Distance(from: i, to: endIndex)
    leftUTF16 = self.utf16Count - rightUTF16
    rightScalars = scalarDistance(from: i, to: endIndex)
    leftScalars = self.unicodeScalarCount - rightScalars
  }

  let left = _counts(upTo: i, utf16: leftUTF16, scalars: leftScalars)
  let right = _counts(from: i, utf16: rightUTF16, scalars: rightScalars)

  assert(left.utf8 + right.utf8 == self.counts.utf8)
  assert(left.utf16 + right.utf16 == self.counts.utf16)
  assert(left.unicodeScalars + right.unicodeScalars == self.counts.unicodeScalars)
  assert(left.characters + right.characters == self.counts.characters)
  return (left, right)
}

func _counts(upTo i: Index, utf16: Int, scalars: Int) -> Counts {
  assert(i > startIndex && i < endIndex)

  var result = Counts(
    utf8: utf8Distance(from: startIndex, to: i),
    utf16: utf16,
    unicodeScalars: scalars,
    characters: 0,
    prefix: 0,
    suffix: 0)

  let firstBreak = self.firstBreak
  let lastBreak = self.lastBreak

  if i <= firstBreak {
    result.characters = 0
    result._prefix = result.utf8
    result._suffix = result.utf8
  } else if i > lastBreak {
    result._characters = self.counts._characters
    result._prefix = self.counts._prefix
    result._suffix = self.counts._suffix - (self.counts.utf8 - result.utf8)
  } else { // i > firstBreak, i <= lastBreak
    result._prefix = self.counts._prefix
    assert(!(firstBreak..<i).isEmpty)
    var state = _CharacterRecognizer()
    let (characters, _, last) = state.consume(self, firstBreak..<i)!
    result.characters = characters
    result.suffix = utf8Distance(from: last, to: i)
  }
  return result
}

func _counts(from i: Index, utf16: Int, scalars: Int) -> Counts {
  assert(i > startIndex && i < endIndex)
  var result = Counts(
    utf8: utf8Distance(from: i, to: endIndex),
    utf16: utf16,
    unicodeScalars: scalars,
    characters: 0,
    prefix: 0,
    suffix: 0)

  let firstBreak = self.firstBreak
  let lastBreak = self.lastBreak

  if i > lastBreak {
    result._characters = 0
    result._prefix = result.utf8
    result._suffix = result.utf8
  } else if i <= firstBreak {
    result._characters = self.counts._characters
    result.prefix = self.counts.prefix - i.utf8Offset
    result._suffix = self.counts._suffix
  } else { // i > firstBreak, i <= lastBreak
    result._suffix = self.counts._suffix
    let prevBreak = characterIndex(roundingDown: i, in: firstBreak..<lastBreak)
    var state = _CharacterRecognizer(partialCharacter: utf8Span(from: prevBreak, to: i))
    if let (characters, first, _) = state.consume(self, i..<lastBreak) {
      assert(first >= i)
      result.characters = characters + 1
      result.prefix = utf8Distance(from: i, to: first)
    } else {
      result.characters = 1
      result.prefix = utf8Distance(from: i, to: lastBreak)
    }
  }
  return result
}

public mutating func next<R>(
  maximumCount: Int,
  with body: (UnsafeBufferPointer<UInt8>) -> (consumed: Int, result: R)
) -> R {
  guard _index < _base.endIndex else {
    let r = body(UnsafeBufferPointer(start: nil, count: 0))
    precondition(r.consumed == 0)
    return r.result
  }
  let ri = _index._rope!
  var ci = _index._chunkIndex.utf8Offset
  var utf8Offset = _index.utf8Offset

  let chunk = _base._rope[ri]
  let slice = chunk._bytes[ci...].prefix(maximumCount)
  assert(!slice.isEmpty)
  let (consumed, result) = body(UnsafeBufferPointer(rebasing: slice))
  precondition(consumed >= 0 && consumed <= slice.count)
  utf8Offset += consumed
  ci += consumed
  let haveMore = ci < chunk._bytes.count

  if haveMore {
    _index = BigString.Index(_utf8Offset: utf8Offset, _rope: ri, chunkOffset: ci)
  } else {
    _index = BigString.Index(
      baseUTF8Offset: _index._utf8BaseOffset + chunk.span.count,
      _rope: _base._rope.index(after: ri),
      chunk: BigString._Chunk.Index(utf8Offset: 0))
  }
  return result
}

