public func scope<ChildState, ChildAction>(
  component: StackState<ChildState>.Component,
  fileID: StaticString = #fileID,
  filePath: StaticString = #filePath,
  line: UInt = #line,
  column: UInt = #column
) -> Store<ChildState, ChildAction>
where State == StackState<ChildState>, Action == StackAction<ChildState, ChildAction> {
  let id = self.id(
    state:
      \.[
        id: component.id,
        fileID: _HashableStaticString(rawValue: fileID),
        filePath: _HashableStaticString(rawValue: filePath),
        line: line,
        column: column
      ],
    action: \.[id: component.id]
  )
  @MainActor
  func open(
    _ core: some Core<StackState<ChildState>, StackAction<ChildState, ChildAction>>
  ) -> any Core<ChildState, ChildAction> {
    IfLetCore(
      base: core,
      cachedState: component.element,
      stateKeyPath:
        \.[
          id: component.id,
          fileID: _HashableStaticString(rawValue: fileID),
          filePath: _HashableStaticString(rawValue: filePath),
          line: line,
          column: column
        ],
      actionKeyPath: \.[id: component.id]
    )
  }
  return self.scope(id: id, childCore: open(self.core))
}

@usableFromInline
func typeName(
  _ type: Any.Type,
  qualified: Bool = true,
  genericsAbbreviated: Bool = true
) -> String {
  var name = _typeName(type, qualified: qualified)
    .replacingOccurrences(
      of: #"\(unknown context at \$[[:xdigit:]]+\)\."#,
      with: "",
      options: .regularExpression
    )
  for _ in 1...10 {  // NB: Only handle so much nesting
    let abbreviated =
      name
      .replacingOccurrences(
        of: #"\bSwift.Optional<([^><]+)>"#,
        with: "$1?",
        options: .regularExpression
      )
      .replacingOccurrences(
        of: #"\bSwift.Array<([^><]+)>"#,
        with: "[$1]",
        options: .regularExpression
      )
      .replacingOccurrences(
        of: #"\bSwift.Dictionary<([^,<]+), ([^><]+)>"#,
        with: "[$1: $2]",
        options: .regularExpression
      )
    if abbreviated == name { break }
    name = abbreviated
  }
  name = name.replacingOccurrences(
    of: #"\w+\.([\w.]+)"#,
    with: "$1",
    options: .regularExpression
  )
  if genericsAbbreviated {
    name = name.replacingOccurrences(
      of: #"<.+>"#,
      with: "",
      options: .regularExpression
    )
  }
  return name
}

private func argumentActionAndSetupScript(
  _ arg: ArgumentInfoV0
) -> (argumentAction: String, setupScript: String?) {
  switch arg.completionKind {
  case .none:
    return ("", nil)

  case .file(let extensions):
    return
      extensions.isEmpty
      ? ("_files", nil)
      : (
        "_files -g '\\''\(extensions.map { "*.\($0.shellEscapeForSingleQuotedString())" }.joined(separator: " "))'\\''",
        nil
      )

  case .directory:
    return ("_files -/", nil)

  case .list(let list):
    let variableName = variableName(arg)
    return (
      "{\(completeFunctionName) \"${\(variableName)[@]}\"}",
      "local -ar \(variableName)=(\(list.map { "'\($0.shellEscapeForSingleQuotedString())'" }.joined(separator: " ")))"
    )

  case .shellCommand(let command):
    return (
      "{local -a list;list=(${(f)\"$(\(command.shellEscapeForSingleQuotedString()))\"});_describe -V \"\" list}",
      nil
    )

  case .custom, .customAsync:
    return (
      "{\(customCompleteFunctionName) \(arg.commonCustomCompletionCall(command: self)) \"${current_word_index}\" \"$(\(cursorIndexInCurrentWordFunctionName))\"}",
      nil
    )

  case .customDeprecated:
    return (
      "{\(customCompleteFunctionName) \(arg.commonCustomCompletionCall(command: self))}",
      nil
    )
  }
}

public static func raw(pretty: Bool) -> Snapshotting {
  return SimplySnapshotting.lines.pullback { (request: URLRequest) in
    let method =
      "\(request.httpMethod ?? "GET") \(request.url?.sortingQueryItems()?.absoluteString ?? "(null)")"

    let headers = (request.allHTTPHeaderFields ?? [:])
      .map { key, value in "\(key): \(value)" }
      .sorted()

    let body: [String]
    do {
      if pretty, #available(iOS 11.0, macOS 10.13, tvOS 11.0, watchOS 4.0, *) {
        body =
          try request.httpBody
          .map { try JSONSerialization.jsonObject(with: $0, options: []) }
          .map {
            try JSONSerialization.data(
              withJSONObject: $0, options: [.prettyPrinted, .sortedKeys])
          }
          .map { ["\n\(String(decoding: $0, as: UTF8.self))"] }
          ?? []
      } else {
        throw NSError(domain: "co.pointfree.Never", code: 1, userInfo: nil)
      }
    } catch {
      body =
        request.httpBody
        .map { ["\n\(String(decoding: $0, as: UTF8.self))"] }
        ?? []
    }

    return ([method] + headers + body).joined(separator: "\n")
  }
